#!/usr/bin/env python3
import csv
import sys


def main():
    input_file = "input.csv"
    output_file = "output.csv"

    data = []
    with open(input_file, newline="", encoding="utf-8") as csvfile:
        reader = csv.reader(csvfile)
        for row in reader:
            if len(row) >= 4 and row[3].lower() == "active":
                name = row[0]
                department = row[1]
                salary = float(row[2])
                data.append((department, salary))

    department_data = {}
    for department, salary in data:
        if department not in department_data:
            department_data[department] = {"total": 0, "count": 0}
        department_data[department]["total"] += salary
        department_data[department]["count"] += 1

    results = []
    for department in sorted(department_data.keys()):
        total_salary = department_data[department]["total"]
        employee_count = department_data[department]["count"]
        avg_salary = round(total_salary / employee_count, 2)
        results.append([department, avg_salary, employee_count])

    with open(output_file, "w", newline="", encoding="utf-8") as csvfile:
        writer = csv.writer(csvfile)
        writer.writerow(["department", "avg_salary", "count"])
        writer.writerows(results)


if __name__ == "__main__":
    main()
